import BlurFade from '@/components/magicui/blur-fade';
import { formatDistanceToNow } from 'date-fns';
import { zhCN } from 'date-fns/locale';
import type { Metadata } from 'next';
import { promises as fs } from 'fs';
import path from 'path';

const BLUR_FADE_DELAY = 0.04;

export const metadata: Metadata = {
  title: 'Thoughts',
  description: '我的碎碎念'
};

interface Thought {
  id: string;
  text: string;
  date: string;
  timestamp: number;
}

interface ThoughtsData {
  thoughts: Thought[];
  lastSync: string | null;
  totalCount: number;
}

async function getThoughts(): Promise<ThoughtsData> {
  try {
    const filePath = path.join(process.cwd(), 'content', 'thoughts.json');
    const fileContents = await fs.readFile(filePath, 'utf8');
    return JSON.parse(fileContents);
  } catch {
    return { thoughts: [], lastSync: null, totalCount: 0 };
  }
}

export default async function ThoughtsPage() {
  const data = await getThoughts();

  return (
    <main className='flex flex-col min-h-[100dvh] space-y-10'>
      <section id='thoughts'>
        <div className='mx-auto w-full max-w-2xl space-y-8'>
          <BlurFade delay={BLUR_FADE_DELAY}>
            <h1 className='text-3xl font-bold tracking-tighter sm:text-5xl'>
              Thoughts
            </h1>
            <p className='text-muted-foreground'>
              来自 Telegram 频道的碎碎念
            </p>
          </BlurFade>

          {data.thoughts.length === 0 ? (
            <BlurFade delay={BLUR_FADE_DELAY * 2}>
              <p className='text-muted-foreground text-center py-12'>
                暂无内容
              </p>
            </BlurFade>
          ) : (
            <div className='space-y-4'>
              {data.thoughts.map((thought, idx) => (
                <BlurFade key={thought.id} delay={BLUR_FADE_DELAY * 2 + idx * 0.05}>
                  <div className='rounded-lg border p-4 space-y-2'>
                    <p className='text-sm leading-7'>{thought.text}</p>
                    <p className='text-xs text-muted-foreground'>
                      {formatDistanceToNow(new Date(thought.date), {
                        addSuffix: true,
                        locale: zhCN
                      })}
                    </p>
                  </div>
                </BlurFade>
              ))}
            </div>
          )}
        </div>
      </section>
    </main>
  );
}
```

