      scanDir(fullPath);
    } else if (entry.isFile() && entry.name.endsWith('.mdx')) {
      checkFile(fullPath);
    }
  }
}

scanDir(blogDir);

if (errors.length > 0) {
  console.log(`Found ${errors.length} files with frontmatter errors:\n`);
  errors.forEach(({ file, error }) => {
    console.log(`❌ ${file}`);
    console.log(`   ${error}\n`);
  });
  process.exit(1);
} else {
  console.log('✅ All frontmatter is valid!');
}

