        if (updateCategory(fullPath)) {
          count++;
          console.log(`Updated: ${path.relative(blogDir, fullPath)}`);
        }
      }
    }
  }

  scanDir(yearPath);
});

console.log(`\nUpdated ${count} posts to "thoughts" category`);

